using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    // Define the order of business lines
    vector<string> business_order = {"electronics", "grocery", "pharmacy", "restaurant"};
    map<string, int> business_map;
    for (int i = 0; i < business_order.size(); ++i) {
        business_map[business_order[i]] = i;
