    vector<pair<string, string>> valid_coupons;
    for (int i = 0; i < code.size(); ++i) {
        if (code[i].length() > 0 && isActive[i] && business_map.find(businessLine[i]) != business_map.end()) {
            // Check if code is valid (alphanumeric and underscore only)
            regex pattern("^[a-zA-Z0-9_]+$");
            if (regex_match(code[i], pattern)) {
                valid_coupons.push_back({code[i], businessLine[i]});
            }
        }
    }

    // Sort by business line order and then by code in dictionary order
    sort(valid_coupons.begin(), valid_coupons.end(), [](const pair<string, string>& a, const pair<string, string>& b) {
        return business_map[a.second] < business_map[b.second] || (business_map[a.second] == business_map[b.second] && a.first < b.first);
    });

    // Extract the codes in the sorted order
    vector<string> result;
    for (const auto& p : valid_coupons) {
        result.push_back(p.first);
    }
    return result;
}
