    sort(valid_coupons.begin(), valid_coupons.end(), 
         [](const pair<string, string>& a, const pair<string, string>& b) {
             return business_order.index(a.second) < business_order.index(b.second) ||
                    (business_order.index(a.second) == business_order.index(b.second) &&
